class Solution:
    def minimumDistance(self, nums):
        n = len(nums)
        best = -1
        for i in range(n):
            for j in range(i + 1, n):
                if nums[j] != nums[i]:
                    continue
                for k in range(j + 1, n):
                    if nums[k] != nums[i]:
                        continue
                    d = abs(i - j) + abs(j - k) + abs(k - i)
                    if best == -1 or d < best:
                        best = d
        return best

