class Solution:
    def minimumDistance(self, nums):
        from collections import defaultdict
        positions = defaultdict(list)
        for i, v in enumerate(nums):
            positions[v].append(i)
        best = -1
        for idxs in positions.values():
            if len(idxs) < 3:
                continue
            for i in range(len(idxs) - 2):
                d = 2 * (idxs[i + 2] - idxs[i])
                if best == -1 or d < best:
                    best = d
        return best

